270	\begin{lemma}[(i.c) Freeness of the relative cotangent of $G$]
271	  \label{lem:GrpObj_omega_free}
272	  \lean{AlgebraicGeometry.GrpObj.omega_free}
273	  \uses{lem:GrpObj_cotangentSpace, lem:GrpObj_mulRight_globalises}
274	  \notready
275	  The relative cotangent presheaf $\Omega_{G/k}$ is a free $\mathcal O_{G}$-module.
276	\end{lemma}
277	
278	\begin{proof}
279	  \uses{lem:GrpObj_cotangentSpace, lem:GrpObj_mulRight_globalises}
280	  By \cref{lem:GrpObj_mulRight_globalises}, $\Omega_{G/k}$ is canonically isomorphic to the pullback along the structure map $G \to \Spec k$ of the $k$-vector space $\mathfrak g^{\vee} = \eta_{G}^{*}\,\Omega_{G/k}$. By \cref{lem:GrpObj_cotangentSpace}, $\mathfrak g^{\vee}$ is a finitely generated free $k$-module. The pullback of a finitely generated free $k$-module along the structure morphism is a finitely generated free $\mathcal O_{G}$-module.
281	\end{proof}
282	
283	\begin{lemma}[(i.c) Rank of the relative cotangent of $G$]
284	  \label{lem:GrpObj_omega_rank_eq_dim}
285	  \lean{AlgebraicGeometry.GrpObj.omega_rank_eq_dim}
286	  \uses{lem:GrpObj_omega_free, lem:GrpObj_lieAlgebra_finrank}
287	  \notready
288	  The (constant) rank of $\Omega_{G/k}$ as a free $\mathcal O_{G}$-module equals $n$, where $n$ is the relative dimension supplied by $[\mathtt{SmoothOfRelativeDimension}\,n\,G.\mathtt{hom}]$.
289	\end{lemma}
290	
291	\begin{proof}
292	  \uses{lem:GrpObj_omega_free, lem:GrpObj_lieAlgebra_finrank}
293	  The rank of the pulled-back bundle equals the $k$-dimension of its fibre. The fibre is $\mathfrak g^{\vee}$, whose $k$-rank equals $n$ by \cref{lem:GrpObj_lieAlgebra_finrank}.
294	\end{proof}
295	
296	\begin{remark}
297	  \label{rem:piece_i_first_target}
298	  \uses{lem:GrpObj_cotangentSpace, lem:GrpObj_lieAlgebra_finrank}
299	  Sub-step (i.a) --- \cref{lem:GrpObj_cotangentSpace} (the definition) plus the rank lemma \cref{lem:GrpObj_lieAlgebra_finrank} --- is the natural first target for the iter-128+ prover lane (closed iter-128 $\to$ iter-132 over a 5-iter span; see STRATEGY.md \S Sequencing piece (i.a) row for the empirical cost trace). Under Replacement (B) the iter-131 strategy-critic Q4 trio$\to$duo collapse demoted the bridge lemma \cref{lem:GrpObj_cotangent_bridge} to a vestigial-on-live-path deferred alternative (see rank-lemma proof Step 3 + footer at \cref{lem:GrpObj_lieAlgebra_finrank}). Sub-steps (i.b) and (i.c) are staged on top of (i.a) and are scheduled for iter-133+ / iter-137+ respectively.
300	\end{remark}
